import Chart from 'chart.js/auto'
import { getDataFromAPI } from "../server/server";

(async function () {
    const apiData = await getDataFromAPI('/v2/ladd').then(data => {
        return data;
    })

    const chartData = apiData?.ac.slice(0, 10).map(data => {
        return { 
            lat: parseFloat(data.lat), 
            lon: parseFloat(data.lon),
            name: data.flight || "Unknown",
            altitude: parseFloat(data.alt_geom || 0),
            category: data.category || "Unknown",
            groundspeed: parseFloat(data.gs || 0),
            emergency: data.emergency
        };
    })

    new Chart(
        document.getElementById('scatterChart'),
        {
            type: 'scatter',
            data: {
                labels: chartData.map(row => row.lat),
                datasets: [
                    {
                        label: 'Planes on Scatter Chart',
                        data: chartData.map(row => ({ x: row.lat, y: row.lon })),
                        pointBackgroundColor: 'blue',
                        pointRadius: 6,
                        pointHoverRadius: 8
                    }
                ]
            },
            options: {
                plugins: {
                    tooltip: {
                        callbacks: {
                            label: function (context) {
                                var label = 'Plane Info:';
                                label += 'Latitude: ' + context.parsed.x;
                                label += 'Longitude: ' + context.parsed.y;
                                label += 'Name: ' + chartData[context.dataIndex].name;
                                label += 'Altitude: ' + chartData[context.dataIndex].altitude;
                                label += 'Category: ' + chartData[context.dataIndex].category;
                                label += 'Groundspeed: ' + chartData[context.dataIndex].groundspeed;
                                label += 'Emergency: ' + chartData[context.dataIndex].emergency;
                                return label;
                            }
                        }
                    }
                }
            }
        }
    );

})();